// Récupérer les données
const topic = $('Définir le sujet').first().json.topic;
const tags = $('Définir le sujet').first().json.tags;
const author = $('Définir le sujet').first().json.author || 'Équipe Mindeon.ai';
const articleContent = $input.first().json.content[0].text;

// Générer le slug à partir du titre
function slugify(str) {
  return str
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 80);
}

const slug = slugify(topic);

// Date du jour
const today = new Date().toISOString().split('T')[0];

// Tags formattés pour le frontmatter YAML
const tagsFormatted = tags
  .split(',')
  .map(t => t.trim())
  .map(t => `  - "${t}"`)
  .join('\n');

// Construire le fichier markdown complet
const frontmatter = `---
title: "${topic}"
description: "${topic} — analyse, conseils pratiques et retours d'expérience de l'équipe Mindeon.ai."
date: ${today}
author: "${author}"
tags:
${tagsFormatted}
---`;

const fullMarkdown = `${frontmatter}\n\n${articleContent}`;

// Encoder en base64 pour l'API GitHub
const base64Content = Buffer.from(fullMarkdown).toString('base64');

return [{
  json: {
    slug,
    filename: `${slug}.md`,
    path: `src/content/articles/${slug}.md`,
    content: base64Content,
    raw: fullMarkdown,
    commitMessage: `feat(articles): add "${topic}"`
  }
}];
